// FIX 5: PII. Generamos un batch_id determinístico por ventana de tiempo
// que sirve como idempotency key para los POST de Zolutium.
const windowStart = new Date();
windowStart.setMinutes(0, 0, 0);
windowStart.setHours(Math.floor(windowStart.getHours() / 6) * 6);
const batchId = `kb-${windowStart.toISOString().replace(/[:.]/g, '-')}`;
return [{ json: { batch_id: batchId, window_start: windowStart.toISOString() } }];

// FIX 1: Paginación. Acumula páginas hasta que la API no devuelva next_cursor.
const items = $('Acumular Conversaciones')?.last?.()?.json?.items || [];
const incoming = $input.first().json?.data || [];
const nextCursor = $input.first().json?.next_cursor || null;
const accumulated = items.concat(incoming);

return [{
  json: {
    items: accumulated,
    cursor: nextCursor,
    has_more: !!nextCursor,
    batch_id: $('Init Batch (idempotency)').first().json.batch_id,
    window_start: $('Init Batch (idempotency)').first().json.window_start
  }
}];

// FIX 5: PII. Solo enviamos a Claude lo mínimo necesario: hash del contact_id,
// canal, tags, texto. Nada de email/teléfono/nombre/documento.
const crypto = require('crypto');
const hashId = id => crypto.createHash('sha256').update(String(id) + ($env.PII_SALT || 'bac-loyalty')).digest('hex').slice(0, 12);

const conv = $('Acumular Conversaciones').first().json.items || [];
const contactos = $('GET Contactos Activos').first().json?.data || [];
const contactosPorId = new Map(contactos.map(c => [c.id, c]));

const dataset = conv.map(c => {
  const contacto = contactosPorId.get(c.contact_id);
  return {
    id_hash: hashId(c.id),
    fecha: c.created_at,
    canal: c.channel,
    texto: (c.messages || []).map(m => `[${m.role}] ${m.content}`).join('\n').slice(0, 4000),
    contacto_segmento: contacto?.segment || null,
    contacto_tier: contacto?.tier || null,
    tags: c.tags || [],
    resuelta: c.resolved === true
  };
});

const stats = {
  total_conversaciones: dataset.length,
  total_contactos: contactos.length,
  resueltas: dataset.filter(d => d.resuelta).length,
  canales: [...new Set(dataset.map(d => d.canal))],
  ventana_horas: 6,
  pii_sanitized: true
};

return [{ json: {
  dataset,
  stats,
  batch_id: $('Acumular Conversaciones').first().json.batch_id
}}];

