// FIX 3: Validación robusta de la salida de Claude.
// Extrae JSON aunque venga envuelto en markdown o con texto antes/después.
const raw = $input.first().json?.content?.[0]?.text
         || $input.first().json?.text
         || $input.first().json?.message?.content
         || '';

function extractJson(s) {
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenced) return fenced[1].trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start >= 0 && end > start) return s.slice(start, end + 1);
  return s;
}

let analisis;
try {
  analisis = JSON.parse(extractJson(raw));
} catch (e) {
  // No abortamos el workflow: marcamos como descarte y continuamos a la rama de error.
  return [{
    json: {
      __invalid_json: true,
      raw_excerpt: raw.slice(0, 500),
      error: e.message,
      batch_id: $('Preparar Datos (PII safe)').first().json.batch_id
    }
  }];
}

const confianza = Number(analisis.confianza ?? 0);
const batchId = $('Preparar Datos (PII safe)').first().json.batch_id;
const timestamp = new Date().toISOString();

return [{
  json: {
    batch_id: batchId,
    timestamp,
    confianza,
    nuevas_faqs: analisis.nuevas_faqs ?? [],
    patrones: analisis.patrones_detectados ?? [],
    brechas: analisis.brechas_kb ?? [],
    acciones: analisis.acciones_recomendadas ?? [],
    descartar: confianza < Number($env.KB_CONFIDENCE_THRESHOLD || 0.6),
    texto_plano: [
      `# Analisis KB ${timestamp}`,
      `Batch: ${batchId}  Confianza: ${confianza}`,
      `## Patrones`, ...(analisis.patrones_detectados || []).map(p => `- ${p}`),
      `## Nuevas FAQs`, ...(analisis.nuevas_faqs || []).map(f => `### ${f.pregunta}\n${f.respuesta_sugerida}`),
      `## Brechas`, ...(analisis.brechas_kb || []).map(b => `- ${b}`)
    ].join('\n')
  }
}];

// Rama de descarte: registrar para auditoría sin tocar la KB.
const j = $input.first().json;
console.log('[KB-7] Batch descartado:', JSON.stringify({
  batch_id: j.batch_id,
  invalid_json: !!j.__invalid_json,
  confianza: j.confianza,
  error: j.error
}));
return [{ json: j }];
